const config = $('Set Config').first().json;
const response = $input.first().json;

// Handle array wrapper - API returns [{success, comments, ...}]
const comments = Array.isArray(response) ? response[0]?.comments : response.comments;

if (!comments || comments.length === 0) {
  return [{ json: { error: 'No comments found', profiles: [] } }];
}

// Deduplicate by profileUrl
const seen = new Set();
const profiles = [];

for (const c of comments) {
  if (c.profileUrl && !seen.has(c.profileUrl)) {
    seen.add(c.profileUrl);
    profiles.push({
      profileId: c.publicIdentifier,
      name: c.authorName || '',
      profileUrl: c.profileUrl,
      competitor: config.competitor,
      sendMessage: config.sendMessage,
      template: config.template,
      dailyLimit: config.dailyLimit
    });
  }
}

return profiles.map(p => ({ json: p }));

const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().split('T')[0];
const DAILY_LIMIT = item.dailyLimit || 8;

// Reset if new day
if (staticData.date !== today) {
  staticData.date = today;
  staticData.count = 0;
}

const count = staticData.count || 0;
const limitReached = count >= DAILY_LIMIT;

return [{ json: { ...item, limitReached, sentToday: count, dailyLimit: DAILY_LIMIT } }];

// Calculate seconds until midnight
const now = new Date();
const tomorrow = new Date(now);
tomorrow.setDate(tomorrow.getDate() + 1);
tomorrow.setHours(0, 0, 5, 0); // 12:00:05 AM

const secondsUntilTomorrow = Math.ceil((tomorrow - now) / 1000);

// Reset counter for new day
const staticData = $getWorkflowStaticData('global');
const newDate = tomorrow.toISOString().split('T')[0];
staticData.date = newDate;
staticData.count = 0;

return [{ json: { ...$input.first().json, waitSeconds: secondsUntilTomorrow, resumeAt: tomorrow.toISOString(), limitReached: false, sentToday: 0 } }];

const profile = $input.first().json;
const item = $('Loop').first().json;

// Skip if competitor employee
const company = (profile.currentCompany || profile.headline || '').toLowerCase();
if (company.includes(item.competitor)) {
  return [{ json: { skip: true, reason: 'competitor_employee', profileId: item.profileId, name: item.name } }];
}

// Build message if enabled
let message = null;
if (item.sendMessage && item.template) {
  const firstName = profile.firstName || item.name?.split(' ')[0] || 'there';
  message = item.template.replace('{firstName}', firstName);
  if (message.length > 300) message = message.slice(0, 297) + '...';
}

return [{ json: { skip: false, profileId: item.profileId, name: item.name, firstName: profile.firstName, message } }];

const res = $input.first().json;
const item = $('Loop').first().json;
const sent = res.success === true;

// Increment daily counter if sent successfully
if (sent) {
  const staticData = $getWorkflowStaticData('global');
  staticData.count = (staticData.count || 0) + 1;
}

return [{ json: { profileId: item.profileId, name: item.name, sent, error: res.error || null } }];

const results = $input.first().json.results || [];
const sent = results.filter(r => r.sent).length;
const skipped = results.filter(r => r.skip).length;
const staticData = $getWorkflowStaticData('global');

return [{ json: {
  status: 'completed',
  total: results.length,
  sent,
  skipped,
  failed: results.length - sent - skipped,
  dailyCountNow: staticData.count || 0,
  results
} }];
